    # C(n, k) = C(n-1, k-1) + C(n-1, k)
    # C(n, 0) = 1; C(0, k) = 0 for n < k
    # C(n, k) = 1 if k == 0 or k == n else C(n-1, k-1) + C(n-1, k)
